* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  font-family: "Neue Haas Grotesk Display Pro";
  text-transform: uppercase;
}

html,
body {
  width: 100vw;
  height: 500vh;
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

canvas {
  position: fixed;
  top: 0;
  left: 0;
}

h1 {
  text-align: center;
  font-size: 10vw;
  font-weight: 300;
  line-height: 100%;
}

h2 {
  font-size: 2.5vw;
  font-weight: 500;
  line-height: 100%;
}

p {
  font-size: 12px;
  font-weight: 500;
  line-height: 100%;
}

.model {
  position: fixed;
  width: 100%;
  height: 100vh;
  background: #fefdfd;
}

section {
  position: relative;
  width: 100vw;
  height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  gap: 1em;
  z-index: 2;
}

.hero h1 {
  margin-bottom: 0.25em;
}

.hero p {
  width: 50%;
  text-align: center;
}

.info {
  gap: 8em;
}

.info .tags {
  width: 60%;
  display: flex;
  gap: 2em;
}

.info h2 {
  width: 75%;
  text-align: center;
}

.info p {
  width: 60%;
  text-align: center;
}

.scan-info {
  position: absolute;
  top: 0;
  width: 100vw;
  display: flex;
  justify-content: space-between;
  padding: 2em;
}

.scan-container {
  width: 280px;
  height: 480px;
  border: 1px solid #000;
  border-radius: 0.5em;
}

.barcode {
  position: absolute;
  bottom: 1em;
  left: 2em;
  width: 200px;
  height: 100px;
}

.purchased {
  position: absolute;
  bottom: 2em;
  right: 2em;
  padding: 0.5em 4em;
  color: red;
  border: 1px solid red;
  border-radius: 2em;
}

.outro h2 {
  width: 70%;
  text-align: center;
}

.lenis.lenis-smooth {
  scroll-behavior: auto !important;
}

.lenis.lenis-smooth [data-lenis-prevent] {
  overscroll-behavior: contain;
}

.lenis.lenis-stopped {
  overflow: clip;
}

.lenis.lenis-smooth iframe {
  pointer-events: none;
}
